Q2 - O(N) runtime



    public int getCount(int nums[], int k) {
    if (nums == null || nums.length == 0) {
      return 0;
    }

    Map<Integer, Integer> map = new HashMap<>();

    for (int n : nums) {
      map.compute(n, (key, v) -> v == null ? 1 : v + 1);
    }

    int result = 0;

    for (int i : nums) {
      if (!map.containsKey(i)) {
        continue;
      }

      if (i * 2 == k) {
        if (map.get(i) > 1) {
          result++;
        }

        map.remove(i);
      }
      else if (map.containsKey(k - i)) {
        result++;
        map.remove(i);
      }
    }

    return result;
    }

