func findDistinctPairsWithSum(_ nums:[Int], _ target:Int)->Int
{
    var complementCount = [Int:Int]()
    for num in nums
    {
        let comp = target-num
        complementCount[comp, default: 0]+=1
    }
    var numPairs = 0
    for num in nums
    {
        if let count = complementCount[num]
        {
            numPairs += count
        }
    }


    return numPairs/2-1
}
